=Analyze the company behind  {{ $json.company_domain }}
.  Return only a valid JSON object following this schema:

{
  "type": "object",
  "properties": {
    "company_name":        { "type": "string" },
    "industry":            { "type": "string" },
    "business_model":      { "type": "string" },
    "target_customers":    { "type": "string" },
    "core_services":       { "type": "array",  "items": { "type": "string" } },
    "geographic_focus":    { "type": "string" },
    "notable_recognition": { "type": "string" },
    "tech_stack":          { "type": "array",  "items": { "type": "string" } }
  }
}

Be factual and concise. Use publicly available web sources only.

{
  "type": "object",
  "properties": {
    "company_name": {
      "type": "string",
      "description": "Official company or organization name"
    },
    "industry": {
      "type": "string",
      "description": "Primary industry classification"
    },
    "business_model": {
      "type": "string",
      "description": "How the organization operates and generates funding or revenue"
    },
    "target_customers": {
      "type": "string",
      "description": "Primary audience or customer segments served"
    },
    "core_services": {
      "type": "array",
      "description": "Main services or offerings provided",
      "items": {
        "type": "string"
      }
    },
    "geographic_focus": {
      "type": "string",
      "description": "Primary geographic area of operation"
    },
    "notable_recognition": {
      "type": "string",
      "description": "Awards, media mentions, or notable recognition"
    },
    "tech_stack": {
      "type": "array",
      "description": "Detected or publicly referenced technologies used by the organization (e.g., CMS, frameworks, analytics, hosting,social media)",
      "items": {
        "type": "string"
      }
    }
  },
  "required": [
    "company_name",
    "industry",
    "business_model",
    "target_customers",
    "core_services",
    "geographic_focus",
    "notable_recognition",
    "tech_stack"
  ]
}

={{
(() => {
  const experiences = $('Get Detail Linkedin Profile').item.json.experience || [];
  const exp = experiences.find(e => e.is_current === true);

  if (!exp) return '';

  return `Current Experience:
• Title: ${exp.title || ''}
• Company: ${exp.company || ''}
• Employment Type: ${exp.employment_type || ''}
• Duration: ${exp.duration || ''}`;
})()
}}

={{
(() => {
  const services = $('Search and Get Company Info').item.json.core_services || [];

  if (!Array.isArray(services) || services.length === 0) return '';

  return services
    .map(service => `• ${service}`)
    .join('\n');
})()
}}

={{
(() => {
  const painArray = $('Generate Pain Point').item.json.output.top_3_pain_points || [];

  if (!Array.isArray(painArray) || painArray.length === 0) return '';

  return painArray
    .map(pain => 
`• ${pain.pain_title || ''}`
    )
    .join('\n');
})()
}}
